// Validate input & auth
var data = $input.first().json;
var qs = data.query || data.params || {};
var headers = data.headers || {};

// Simple API key auth (à remplacer par JWT en prod)
var apiKey = String(headers['x-api-key'] || headers['X-Api-Key'] || qs.apiKey || '').trim();
var validKey = 'talosprimes-chat-admin-2026'; // TODO: move to env/credentials

if (apiKey !== validKey) {
  return [{ json: { error: true, code: 401, message: 'Unauthorized: API key invalide' }}];
}

var sessionId = String(qs.sessionId || '').replace(/[^a-zA-Z0-9]/g, '').substring(0, 34);
var limit = Math.min(parseInt(qs.limit) || 50, 200);
var offset = Math.max(parseInt(qs.offset) || 0, 0);
var decrypt = String(qs.decrypt || 'false') === 'true';

return [{ json: { error: false, sessionId, limit, offset, decrypt }}];

