={{ (function() {
  var d = $input.first().json;
  var decrypt = d.decrypt;

  // If specific session
  if (d.sessionId) {
    if (decrypt) {
      // Use decrypted view
      return "SELECT id, session_id, message, created_at FROM v_chat_histories_decrypted "
        + "WHERE session_id = '" + d.sessionId + "' ORDER BY created_at ASC LIMIT " + d.limit + " OFFSET " + d.offset;
    } else {
      return "SELECT id, session_id, CASE WHEN message_encrypted IS NOT NULL THEN '{\"encrypted\": true}'::jsonb ELSE message END as message, "
        + "(message_encrypted IS NOT NULL) as is_encrypted, created_at "
        + "FROM n8n_chat_histories WHERE session_id = '" + d.sessionId + "' ORDER BY created_at ASC LIMIT " + d.limit + " OFFSET " + d.offset;
    }
  }

  // List all sessions (grouped)
  return "SELECT session_id, COUNT(*) as message_count, "
    + "MIN(created_at) as first_message, MAX(created_at) as last_message, "
    + "bool_or(message_encrypted IS NOT NULL) as has_encrypted "
    + "FROM n8n_chat_histories GROUP BY session_id "
    + "ORDER BY MAX(created_at) DESC LIMIT " + d.limit + " OFFSET " + d.offset;
})() }}

