// Format response
var rows = $('05. Query Chat History').all();
var input = $('02. Validate Auth').first().json;
var results = [];

for (var i = 0; i < rows.length; i++) {
  var r = rows[i].json || rows[i];
  results.push(r);
}

var response = { success: true };

if (input.sessionId) {
  response.sessionId = input.sessionId;
  response.decrypted = input.decrypt;
  response.messages = results;
  response.count = results.length;
} else {
  response.sessions = results;
  response.count = results.length;
}

return [{ json: response }];
